// 签名路径总长(渲染所用 chrome-headless-shell 中 getTotalLength() 实测值)。
// 注意不能用 pathLength="100" 归一化:Chrome 对多子路径 <path> 设置
// pathLength 后会整体禁用虚线(实测),故直接采用真实长度。
export const SIGNATURE_PATH_TOTAL_LENGTH = 2109.58;

export type SignaturePathSpec = {
  d: string;
  length: number;
};

export type SignatureData = {
  viewBox: {x: number; y: number; width: number; height: number};
  paths: SignaturePathSpec[];
};

/** 内置签名:单 path + 常量长度,不 fetch,保证默认输出逐帧一致。 */
export const BUILTIN_SIGNATURE: SignatureData = {
  viewBox: {...SIGNATURE_VIEWBOX},
  paths: [{d: SIGNATURE_PATH_D, length: SIGNATURE_PATH_TOTAL_LENGTH}],
};

const parseViewBox = (raw: string | null): SignatureData['viewBox'] => {
  if (!raw) {
    throw new Error('签名 SVG 缺少 viewBox 属性(必须有 viewBox)');
  }
  const parts = raw.trim().split(/[\s,]+/).map(Number);
  if (parts.length !== 4 || parts.some((n) => !Number.isFinite(n))) {
    throw new Error(`签名 SVG 的 viewBox 无法解析: ${raw}`);
  }
  const [x, y, width, height] = parts;
  if (width <= 0 || height <= 0) {
    throw new Error(`签名 SVG 的 viewBox 宽高必须为正: ${raw}`);
  }
  return {x, y, width, height};
};

const measurePathLengths = (ds: string[]): number[] => {
  const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('aria-hidden', 'true');
  svg.style.cssText = 'position:absolute;width:0;height:0;overflow:hidden;visibility:hidden';
  document.body.appendChild(svg);
  try {
    return ds.map((d) => {
      const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      path.setAttribute('d', d);
      svg.appendChild(path);
      const length = path.getTotalLength();
      if (!Number.isFinite(length) || length <= 0) {
        throw new Error('签名 SVG 某条 path 长度为 0 或无效');
      }
      return length;
    });
  } finally {
    svg.remove();
  }
};

/** 解析自定义签名 SVG 文本 → viewBox + 各 path 的 d 与实测长度。 */
export const parseSignatureSvg = (svgText: string): SignatureData => {
  const doc = new DOMParser().parseFromString(svgText, 'image/svg+xml');
  const parseError = doc.querySelector('parsererror');
  if (parseError) {
    throw new Error('签名 SVG 解析失败:不是合法的 XML/SVG');
  }
  const svg = doc.querySelector('svg');
  if (!svg) {
    throw new Error('签名 SVG 缺少 <svg> 根元素');
  }
  const unsupported = Array.from(
    svg.querySelectorAll('text, rect, circle, ellipse, line, polyline, polygon'),
  );
  if (unsupported.length > 0) {
    const tags = [...new Set(unsupported.map((el) => el.tagName.toLowerCase()))].join(', ');
    throw new Error(
      `签名 SVG 只识别 <path>(请先把文字/形状转成路径)。不支持: ${tags}`,
    );
  }
  const pathEls = Array.from(svg.querySelectorAll('path'));
  if (pathEls.length === 0) {
    throw new Error('签名 SVG 中没有 <path> 元素');
  }
  const ds = pathEls.map((el, i) => {
    const d = el.getAttribute('d');
    if (!d?.trim()) {
      throw new Error(`签名 SVG 第 ${i + 1} 个 <path> 缺少 d 属性`);
    }
    return d;
  });
  const lengths = measurePathLengths(ds);
  return {
    viewBox: parseViewBox(svg.getAttribute('viewBox')),
    paths: ds.map((d, i) => ({d, length: lengths[i]})),
  };
};

/**
 * 加载签名数据。无 src 时立即返回内置签名;有 src 时 fetch + 解析 + 测长,
 * 经 delayRender 阻塞渲染直到就绪。解析失败/缺失会抛错(不静默回退)。
 */
export const useSignatureData = (src?: string): SignatureData | null => {
  const [data, setData] = useState<SignatureData | null>(() => (src ? null : BUILTIN_SIGNATURE));

  useEffect(() => {
    if (!src) {
      setData(BUILTIN_SIGNATURE);
      return;
    }
    const handle = delayRender(`Load signature SVG: ${src}`);
    let cancelled = false;
    let settled = false;
    (async () => {
      try {
        const url = staticFile(src.replace(/^\.\//, ''));
        const res = await fetch(url);
        if (!res.ok) {
          throw new Error(`签名 SVG 无法加载 (${res.status}): ${src}`);
        }
        const text = await res.text();
        const parsed = parseSignatureSvg(text);
        if (cancelled) return;
        setData(parsed);
        settled = true;
        continueRender(handle);
      } catch (error) {
        if (cancelled) return;
        // 解析失败/文件缺失 → 终止渲染,不静默回退内置签名
        settled = true;
        cancelRender(error instanceof Error ? error : new Error(String(error)));
      }
    })();
    return () => {
      cancelled = true;
      if (!settled) continueRender(handle);
    };
  }, [src]);

  return data;
};

/**
 * 个人签名字形,纯展示组件:不含定位与配色,颜色经 currentColor 继承。
 * 支持多 path(自定义签名并行描边);pathProps 为统一属性,或按 path 索引返回。
 */
export const Signature: React.FC<{
  style?: React.CSSProperties;
  data?: SignatureData;
  pathProps?:
    | React.SVGProps<SVGPathElement>
    | ((path: SignaturePathSpec, index: number) => React.SVGProps<SVGPathElement>);
}> = ({style, data = BUILTIN_SIGNATURE, pathProps}) => {
  const {viewBox, paths} = data;
  return (
    <svg
      viewBox={`${viewBox.x} ${viewBox.y} ${viewBox.width} ${viewBox.height}`}
      style={style}
    >
      {paths.map((path, index) => {
        const extra =
          typeof pathProps === 'function' ? pathProps(path, index) : (pathProps ?? {});
        return (
          <path
            key={index}
            fillRule="evenodd"
            fill="currentColor"
            d={path.d}
            {...extra}
          />
        );
      })}
    </svg>
  );
};
